function setSyncStatus(st){
  let b=$('#syncStatusBadge');if(!b)return;
  if(!sp){b.style.display='none';return}
  b.style.display='';
  if(st==='synced'){b.style.background='#e2fbf0';b.style.color='#0d744d';b.style.borderColor='#a7f3d0';b.textContent='● Đã đồng bộ'}
  if(st==='saving'){b.style.background='#fffbeb';b.style.color='#b45309';b.style.borderColor='#fef3c7';b.textContent='● Đang lưu...'}
  if(st==='offline'){b.style.background='#fee2e2';b.style.color='#b91c1c';b.style.borderColor='#fecaca';b.textContent='● Chưa đồng bộ (Offline)'}
  if(st==='checking'){b.style.background='#f1f5f9';b.style.color='#475569';b.style.borderColor='#cbd5e1';b.textContent='● Đang kết nối...'}
}
async function syncFromSupabase(silent=false){
  if(!sp)return;
  setSyncStatus('checking');
  try{
    let [usersRes,staffRes,ordersRes]=await Promise.all([
      sp.from('app_users').select('*'),
      sp.from('app_staff').select('*'),
      sp.from('app_orders').select('*')
    ]);
    if(usersRes.error)throw usersRes.error;
    if(staffRes.error)throw staffRes.error;
    if(ordersRes.error)throw ordersRes.error;
    let users = (usersRes.data || []).map(u => {
      let data = {...u};
      if(data.created_at){
        data.createdAt = data.created_at;
        delete data.created_at;
      }
      return data;
    });
    db.users = users.length ? users : [INITIAL_ADMIN];
    if(!db.users.some(u=>u.username==='admin')){
      db.users.push(INITIAL_ADMIN);
      syncUserToSupabase(INITIAL_ADMIN);
    }
    db.staff=staffRes.data||[];
    db.orders=ordersRes.data||[];
    localStorage.setItem('gomita-flow-v1',JSON.stringify(db));
    setSyncStatus('synced');
    render();
    if(!silent)toast('Đã đồng bộ dữ liệu mới nhất từ Cloud.');
  }catch(e){
    console.error('Supabase sync down failed:',e);
    setSyncStatus('offline');
    if(!silent)toast('Lỗi kết nối Cloud. Đang chạy offline bằng bộ nhớ máy.');
  }
}
async function syncOrderToSupabase(o){
  if(!sp)return;
  setSyncStatus('saving');
  try{
    let {error}=await sp.from('app_orders').upsert(o);
    if(error)throw error;
    setSyncStatus('synced');
  }catch(e){
    console.error('Supabase order upsert failed:',e);
    setSyncStatus('offline');
  }
}
async function syncUserToSupabase(u){
  if(!sp)return;
  setSyncStatus('saving');
  try{
    let data={...u};
    if(data.createdAt){
      data.created_at=data.createdAt;
      delete data.createdAt;
    }
    let {error}=await sp.from('app_users').upsert(data);
    if(error)throw error;
    setSyncStatus('synced');
  }catch(e){
    console.error('Supabase user upsert failed:',e);
    setSyncStatus('offline');
  }
}
async function syncStaffToSupabase(staffList){
  if(!sp)return;
  setSyncStatus('saving');
  try{
    let {error:delErr}=await sp.from('app_staff').delete().neq('id','');
    if(delErr)throw delErr;
    if(staffList.length){
      let {error}=await sp.from('app_staff').insert(staffList);
      if(error)throw error;
    }
    setSyncStatus('synced');
  }catch(e){
    console.error('Supabase staff sync failed:',e);
    setSyncStatus('offline');
  }
}
async function uploadAllToSupabase(){
  if(!sp)return;
  setSyncStatus('saving');
  try{
    if(db.users.length)await sp.from('app_users').upsert(db.users);
    if(db.staff.length){
      await sp.from('app_staff').delete().neq('id','');
      await sp.from('app_staff').insert(db.staff);
    }
    if(db.orders.length)await sp.from('app_orders').upsert(db.orders);
    setSyncStatus('synced');
    toast('Đã đồng bộ dữ liệu nội bộ lên Cloud thành công.');
  }catch(e){
    console.error('Supabase bulk upload failed:',e);
    setSyncStatus('offline');
  }
}
let db=load();
function load(){
  try{
    let old=JSON.parse(localStorage.getItem('gomita-flow-v1'));
    if(!old||old.version!==2)return seed();
    old.users=old.users?.length?old.users:[INITIAL_ADMIN];
    old.staff=old.staff||[];
    old.orders=(old.orders||[]).filter(o=>!['o1','o2','o3','o4'].includes(o.id));
    if(!old.users.some(u=>u.id===old.currentUser&&u.active))old.currentUser=old.users.find(u=>u.active)?.id;
    old.backupUrl=old.backupUrl||'';
    old.lastBackupAt=old.lastBackupAt||null;
    old.orders.forEach(o=>{
      o.accessoriesList=o.accessoriesList||'';
      (o.extras||[]).forEach(x=>{if(!x.status)x.status='Đã thanh toán';if(!x.payer)x.payer='Khách hàng';});
      (o.costs||[]).forEach(x=>{if(!x.status)x.status='Đã thanh toán';if(!x.payer)x.payer='Công ty';});
    });
    return old;
  }catch{
    return seed();
  }
}
function save(){
  localStorage.setItem('gomita-flow-v1',JSON.stringify(db));
}
