function calc(o){let extrasConfirmed=(o.extras||[]).filter(x=>x.status!=='Chờ xác nhận'),customerCompany=extrasConfirmed.filter(x=>x.type==='Khách trả'||x.type==='Khách trả (Công ty ứng)').reduce((s,x)=>s+x.amount,0),customerDirect=extrasConfirmed.filter(x=>x.type==='Khách trả (Trực tiếp)').reduce((s,x)=>s+x.amount,0),workshop=extrasConfirmed.filter(x=>x.type==='Xưởng chịu').reduce((s,x)=>s+x.amount,0),confirmed=(o.payments||[]).filter(x=>x.status==='Đã xác nhận').reduce((s,x)=>s+x.amount,0)+customerDirect,labor=(o.labor||[]).filter(x=>x.status==='Đã chốt').reduce((s,x)=>s+x.days*x.rate+(x.allowance||0),0),costsConfirmed=(o.costs||[]).filter(x=>x.status!=='Chờ xác nhận').reduce((s,x)=>s+x.amount,0),costs=costsConfirmed+workshop+labor+customerCompany+customerDirect,revenue=Number(o.quote||0)+customerCompany+customerDirect;return{customer:customerCompany+customerDirect,workshop,confirmed,labor,costs,revenue,debt:revenue-confirmed,profit:revenue-costs,margin:revenue?(revenue-costs)/revenue*100:0}}
function user(){return db.users.find(x=>x.id===db.currentUser)||db.users.find(x=>x.active)||INITIAL_ADMIN} function canEdit(o){return !o.locked||['Giám đốc','Admin'].includes(user().role)} function log(o,text){o.logs=o.logs||[];o.logs.unshift({id:uid(),text,by:user().name,at:new Date().toISOString()})}
function canAddData(type){let r=user().role;if(['Giám đốc','Admin'].includes(r))return true;if(type==='costs')return ['Kế toán','Quản lý đơn hàng','Quản lý sản xuất'].includes(r);if(type==='payments')return ['Kế toán','Quản lý đơn hàng'].includes(r);if(type==='labor')return r==='Quản lý sản xuất';if(type==='extras')return ['Quản lý đơn hàng','Quản lý sản xuất'].includes(r);return false}
