function renderBoard(){let q=$('#search').value.toLowerCase(),sf=$('#statusFilter').value,pf=$('#priorityFilter').value,orders=db.orders.filter(o=>!o.deletedAt && (sf?o.stage===sf:o.stage!=='Lưu trữ') && (!q||[o.code,o.customer,o.address,o.phone.slice(-3)].join(' ').toLowerCase().includes(q))&&(!pf||o.priority===pf));let active=db.orders.filter(o=>!['Hoàn công','Lưu trữ'].includes(o.stage) && !o.deletedAt),val=active.reduce((s,o)=>s+calc(o).revenue,0);$('#summaryLine').textContent=`${active.length} đơn đang chạy · Giá trị ${money(val)}`;let stagesToRender=sf==='Lưu trữ'?['Lưu trữ']:STAGES;$('#board').innerHTML=stagesToRender.map(stage=>{let list=orders.filter(o=>o.stage===stage);return `<div class="column" data-stage="${stage}"><div class="colhead"><span>${stage}</span><span class="count">${list.length}</span></div><div class="cards">${list.map(card).join('')}</div></div>`}).join('');$$('.card').forEach(x=>{x.onclick=()=>openOrder(x.dataset.id);x.ondragstart=e=>{x.classList.add('dragging');e.dataTransfer.setData('text/plain',x.dataset.id)};x.ondragend=()=>x.classList.remove('dragging')});$$('.column').forEach(c=>{c.ondragover=e=>e.preventDefault();c.ondrop=e=>requestTransition(e.dataTransfer.getData('text/plain'),c.dataset.stage)});let overdue=active.filter(o=>o.due<today()).length,soon=active.filter(o=>o.due>=today()&&o.due<=datePlus(3)).length,unconfirmed=db.orders.filter(o=>!o.deletedAt).reduce((s,o)=>s+o.payments.filter(p=>p.status!=='Đã xác nhận').length,0),unfinished=db.orders.filter(o=>!o.deletedAt && o.labor.some(l=>l.status==='Chưa chốt')).length;$('#alerts').innerHTML=[[overdue,'đơn quá hạn'],[soon,'đơn sắp đến hạn'],[unconfirmed,'khoản thu chờ xác nhận'],[unfinished,'công chưa chốt']].filter(x=>x[0]).map(x=>`<div class="alert">⚠ ${x[0]} ${x[1]}</div>`).join('')}
