function tabContent(o,t,edit){let c=calc(o),dis=edit?'':'disabled';if(t==='info')return `<div class="grid"><div class="field"><label>Tên khách hàng *</label><input name="customer" value="${esc(o.customer)}" ${dis}></div><div class="field"><label>Số điện thoại *</label><input name="phone" value="${esc(o.phone)}" ${dis}></div><div class="field"><label>Địa chỉ *</label><input name="address" value="${esc(o.address)}" ${dis}></div><div class="field span3"><label>Nội dung đơn hàng</label><textarea name="content" ${dis}>${esc(o.content)}</textarea></div><div class="field"><label>Trạng thái</label><div style="display:flex;gap:8px;align-items:center;"><input value="${esc(o.stage)}" disabled style="flex:1;"><input type="hidden" name="stage" value="${esc(o.stage)}">${edit&&canMoveFrom(o.stage)?`<button type="button" id="transitionBtn" class="primary" style="min-height:36px;padding:6px 12px;font-size:12px;white-space:nowrap;">→ Chuyển bước</button>`:''}</div></div><div class="field"><label>Người phụ trách</label><select name="owner" ${dis}>${db.users.filter(x=>x.active).map(x=>`<option ${x.name===o.owner?'selected':''}>${esc(x.name)}</option>`)}</select></div><div class="field"><label>Ưu tiên</label><select name="priority" ${dis}>${['Gấp','Bình thường','Chưa gấp'].map(x=>`<option ${x===o.priority?'selected':''}>${x}</option>`)}</select></div><div class="field"><label>Ngày hẹn</label><input type="date" name="due" value="${o.due}" ${dis}></div><div class="field"><label>Nguồn đơn hàng</label><select name="source" ${dis}><option value="">-- Chọn nguồn đơn --</option>${SOURCES.map(x=>`<option ${x===o.source?'selected':''}>${esc(x)}</option>`).join('')}</select></div><div class="field"><label>Việc cần làm tiếp theo</label><input name="next" value="${esc(o.next)}" ${dis}></div><div class="field span2"><label>Ghi chú nhanh</label><textarea name="note" ${dis}>${esc(o.note)}</textarea></div><div class="field"><label>Ghi chú Zalo</label><textarea name="zalo" ${dis}>${esc(o.zalo)}</textarea></div><div class="field"><label>Giá dự toán sản xuất *</label><input type="number" name="estimateProduction" value="${o.estimateProduction||0}" ${dis}></div><div class="field"><label>Giá báo phần sản xuất *</label><input type="number" name="quoteProduction" value="${o.quoteProduction||0}" ${dis}></div><div class="field"><label>Giá báo phần phụ kiện *</label><input type="number" name="quoteAccessory" value="${o.quoteAccessory||0}" ${dis}></div><div class="field span3"><label>Danh sách phụ kiện (kế toán theo dõi & đặt hàng)</label><textarea name="accessoriesList" ${dis} placeholder="Danh sách bản lề, ray trượt, tay nắm tủ...">${esc(o.accessoriesList)}</textarea></div></div>`;
if(t==='finance'){let laborList=(o.labor||[]).filter(x=>x.status==='Đã chốt'),laborRaFile=laborList.filter(x=>x.stage==='Ra file').reduce((s,x)=>s+x.days*x.rate+(x.allowance||0),0),laborSanXuat=laborList.filter(x=>x.stage==='Sản xuất').reduce((s,x)=>s+x.days*x.rate+(x.allowance||0),0),laborLapDat=laborList.filter(x=>x.stage==='Lắp đặt').reduce((s,x)=>s+x.days*x.rate+(x.allowance||0),0),boxes=[['Doanh thu',c.revenue],['Đã thu',c.confirmed],['Còn phải thu',c.debt],['Tổng chi phí',c.costs],['Lãi / lỗ',c.profit],['Tỷ lệ lãi',c.margin.toFixed(1)+'%',1],['Giá dự toán',o.estimate],['Tổng nhân công',c.labor],['Nhân công Ra file',laborRaFile],['Nhân công Sản xuất',laborSanXuat],['Nhân công Lắp đặt',laborLapDat]];return `<div class="finance" style="grid-template-columns:repeat(auto-fit,minmax(220px,1fr));">${boxes.map(x=>`<div class="finbox"><small>${x[0]}</small><b class="${(x[0].includes('Lãi')&&c.profit<0)||x[0].includes('Còn')&&c.debt>0?'danger':''}">${x[2]?x[1]:money(x[1])}</b></div>`).join('')}</div><h3 class="sectiontitle">Công thức</h3><p>Doanh thu = Giá báo khách + Phát sinh khách trả.<br>Chi phí = Sản xuất + Phụ kiện + Nhân công + Vận chuyển + Xưởng chịu + Chi phí khác.</p>`;}
let map={extras:['Phát sinh','Thêm phát sinh'],payments:['Các lần thu','Thêm khoản thu'],costs:['Các khoản chi','Thêm chi phí'],labor:['Công thực hiện','Thêm nhân sự / công']};if(map[t])return `<div class="pagehead"><h3>${map[t][0]}</h3>${edit&&canAddData(t)?`<button type="button" class="primary" data-add="${t}">＋ ${map[t][1]}</button>`:''}</div>${listItems(o,t,edit)}`;
if(t==='logs'){
  let assignments=o.stageAssignments||[],logMap={};assignments.forEach(a=>{logMap[a.stage]=a});
  let rows=STAGES.map(stage=>{
    let a=logMap[stage];
    if(!a)return `<tr><td><b>${esc(stage)}</b></td><td>—</td><td>—</td><td>—</td><td>—</td></tr>`;
    let staffStr='—';
    if(a.workers&&a.workers.length){
      staffStr=a.workers.map(w=>{let s=db.staff.find(x=>x.id===w.id);return `${s?s.name:w.id} (${w.days} công)`}).join('<br>');
    }else if(a.staff&&a.staff.length){
      staffStr=a.staff.join(', ');
    }
    return `<tr><td><b>${esc(stage)}</b></td><td><b>${esc(a.by)}</b></td><td>${new Date(a.at).toLocaleString('vi-VN')}</td><td>${staffStr}</td><td><small>${esc(a.note||'—')}</small></td></tr>`;
  }).join('');
  return `<table class="data" style="font-size:12px;"><thead><tr><th>Công đoạn</th><th>Người chuyển (Cột)</th><th>Thời gian (Ô)</th><th>Nhân sự & Công (Ô)</th><th>Ghi chú bàn giao</th></tr></thead><tbody>${rows}</tbody></table><h3 class="sectiontitle" style="margin-top:18px;">Lịch sử hoạt động hệ thống</h3><div class="log-history" style="max-height:160px;overflow:auto;background:#fbfcfe;padding:12px;border:1px solid var(--line);border-radius:12px;">${(o.logs||[]).length?o.logs.map(l=>`<div class="log" style="font-size:12px;padding:4px 0;border-bottom:1px dashed #eee;"><b>${esc(l.text)}</b> · <small>${esc(l.by)}</small> · <time style="color:var(--muted);">${new Date(l.at).toLocaleString('vi-VN')}</time></div>`).join(''):'<div class="empty">Chưa có hoạt động.</div>'}</div>`;
}
return '';}
function listItems(o,t,edit){let a=o[t]||[];if(!a.length)return '<div class="empty">Chưa có dữ liệu.</div>';return a.map(x=>{let main='',meta='',amt='',actionBtns='';if(t==='extras'){main=x.text;meta=`${x.type} · Ai thanh toán: ${esc(x.payer||'—')} · ${x.status||'Chưa thanh toán'} · ${x.by}`;amt=money(x.amount);if(x.status!=='Đã thanh toán'&&['Kế toán','Admin','Giám đốc'].includes(user().role)){actionBtns+=`<button type="button" data-pay-kind="extras" data-pay-id="${x.id}">Đã thanh toán</button>`}}if(t==='payments'){main=`Thu ngày ${fmtDate(x.date)} · ${x.method}`;meta=x.status+(x.confirmedBy?' · '+x.confirmedBy:'');amt=money(x.amount);if(x.status!=='Đã xác nhận'&&user().role==='Kế toán'){actionBtns+=`<button type="button" data-confirm="${x.id}">Xác nhận</button>`}}if(t==='costs'){main=x.text;meta=`${x.type} · Ai thanh toán: ${esc(x.payer||'—')} · ${x.status||'Chưa thanh toán'} · ${x.by}`;amt=money(x.amount);if(x.status!=='Đã thanh toán'&&['Kế toán','Admin','Giám đốc'].includes(user().role)){actionBtns+=`<button type="button" data-pay-kind="costs" data-pay-id="${x.id}">Đã thanh toán</button>`}}if(t==='labor'){main=x.staff+' · '+x.stage;meta=`${x.days||0} công × ${money(x.rate)}${x.allowance?' + '+money(x.allowance)+' phụ phí':''} · ${x.status}`;amt=money((x.days||0)*x.rate+(x.allowance||0));if(edit&&canAddData('labor')){actionBtns+=`<button type="button" data-edit-labor="${x.id}" style="margin-right:4px;">Sửa</button>`}}return `<div class="listitem"><div><b>${esc(main)}</b><br><small>${esc(meta)}</small></div><b>${amt}</b><div>${actionBtns}${edit&&canAddData(t)?`<button type="button" data-kind="${t}" data-delete="${x.id}">×</button>`:''}</div></div>`}).join('')}
function saveOrder(o,isExisting){let f=new FormData($('#orderForm'));['customer','phone','address','content','owner','priority','due','next','note','zalo','accessoriesList','source'].forEach(k=>o[k]=f.get(k));o.estimateProduction=Number(f.get('estimateProduction')||0);o.quoteProduction=Number(f.get('quoteProduction')||0);o.quoteAccessory=Number(f.get('quoteAccessory')||0);o.estimate=o.estimateProduction;o.quote=o.quoteProduction+o.quoteAccessory;if(!o.customer||!o.phone||!o.address)return toast('Vui lòng nhập tên, điện thoại và địa chỉ.');if(!isExisting){let short=o.address.split(',')[0].trim();o.code=`${o.customer} - ${short} - ${o.phone.slice(-3)}`;o.source=o.source||'';db.orders.unshift(o);log(o,'Tạo đơn hàng')}else log(o,'Cập nhật hồ sơ đơn hàng');render();$('#orderDialog').close();toast('Đã lưu hồ sơ');syncOrderToSupabase(o)}
function quickAdd(o,type){if(!canAddData(type))return toast('Bạn không có quyền thực hiện thao tác này.');let titles={extras:'Thêm phát sinh',payments:'Thêm khoản thu',costs:'Thêm chi phí',labor:'Thêm nhân sự / công'};$('#quickTitle').textContent=titles[type];let h='';if(type==='extras')h=`<div class="grid"><div class="field span2"><label>Nội dung *</label><input name="text" required></div><div class="field"><label>Số tiền *</label><input type="number" name="amount" required></div><div class="field"><label>Loại phát sinh</label><select name="type"><option>Khách trả (Công ty ứng)</option><option>Khách trả (Trực tiếp)</option><option>Xưởng chịu</option><option>Nội bộ/chưa tính</option></select></div><div class="field"><label>Ai thanh toán *</label><input name="payer" placeholder="Người thanh toán..." required></div>${['Kế toán','Admin','Giám đốc'].includes(user().role)?`<div class="field"><label>Trạng thái thanh toán</label><select name="status"><option>Chưa thanh toán</option><option>Đã thanh toán</option></select></div>`:''}<div class="field span3"><label>Ghi chú</label><input name="note"></div></div>`;if(type==='payments')h=`<div class="grid"><div class="field"><label>Ngày thu</label><input type="date" name="date" value="${today()}"></div><div class="field"><label>Số tiền</label><input type="number" name="amount" required></div><div class="field"><label>Hình thức</label><select name="method"><option>Chuyển khoản</option><option>Tiền mặt</option></select></div><div class="field span3"><label>Ghi chú</label><input name="note"></div></div>`;if(type==='costs')h=`<div class="grid"><div class="field span2"><label>Nội dung chi *</label><input name="text" required></div><div class="field"><label>Số tiền *</label><input type="number" name="amount" required></div><div class="field"><label>Loại chi</label><select name="type"><option>Sản xuất</option><option>Phụ kiện</option><option>Nhân công</option><option>Vận chuyển</option><option>Chi phí khác</option></select></div><div class="field"><label>Ai thanh toán *</label><input name="payer" placeholder="Người chi/đơn vị..." required></div>${['Kế toán','Admin','Giám đốc'].includes(user().role)?`<div class="field"><label>Trạng thái thanh toán</label><select name="status"><option>Chưa thanh toán</option><option>Đã thanh toán</option></select></div>`:''}<div class="field span3"><label>Ghi chú</label><input name="note"></div></div>`;if(type==='labor')h=`<div class="grid"><div class="field"><label>Công đoạn</label><select name="stage">${STAGES.slice(3,6).map(x=>`<option>${x}</option>`)}</select></div><div class="field"><label>Nhân sự</label><select name="staff">${db.staff.map(x=>`<option value="${x.id}">${x.name} · ${money(x.rate)}/công</option>`)}<option value="outsource">-- Thuê ngoài --</option></select></div><div class="field" id="daysField"><label>Số công (để 0 nếu chưa chốt)</label><input type="number" step="0.25" min="0" name="days" value="0"></div><div class="field" id="allowanceField"><label>Phụ phí công tác</label><input type="number" name="allowance" value="0" min="0"></div><div class="field" id="amountField" style="display:none;"><label>Số tiền thuê ngoài *</label><input type="number" name="outsourceAmount" value="0" min="0"></div><div class="field"><label>Trạng thái</label><select name="status"><option>Chưa chốt</option><option>Đã chốt</option></select></div></div>`;$('#quickBody').innerHTML=`<div class="formcontent">${h}</div><div class="modalactions"><button value="cancel" formnovalidate>Hủy</button><button type="button" id="quickSave" class="primary">Lưu</button></div>`;if(type==='labor'){let staffSelect=$('#quickForm [name="staff"]'),daysField=$('#daysField'),allowanceField=$('#allowanceField'),amountField=$('#amountField');staffSelect.onchange=()=>{if(staffSelect.value==='outsource'){daysField.style.display='none';allowanceField.style.display='none';amountField.style.display='block'}else{daysField.style.display='block';allowanceField.style.display='block';amountField.style.display='none'}}} $('#quickDialog').showModal();$('#quickSave').onclick=()=>{let f=new FormData($('#quickForm')),x={id:uid(),by:user().name,at:new Date().toISOString(),note:f.get('note')||''};if(type==='extras'||type==='costs'){let st=f.get('status')||'Chưa thanh toán';if(!['Kế toán','Admin','Giám đốc'].includes(user().role))st='Chưa thanh toán';Object.assign(x,{text:f.get('text'),amount:Number(f.get('amount')),type:f.get('type'),payer:f.get('payer').trim(),status:st});if(!x.payer)return toast('Vui lòng điền người thanh toán.')}if(type==='payments')Object.assign(x,{date:f.get('date'),amount:Number(f.get('amount')),method:f.get('method'),status:user().role==='Kế toán'?'Đã xác nhận':'Chờ xác nhận',confirmedBy:user().role==='Kế toán'?user().name:''});if(type==='labor'){let staffVal=f.get('staff');if(staffVal==='outsource'){let amt=Number(f.get('outsourceAmount')||0);Object.assign(x,{stage:f.get('stage'),staff:'Thuê ngoài',days:1,rate:amt,allowance:0,status:f.get('status')});if(x.status==='Đã chốt'&&!x.rate)return toast('Số tiền thuê ngoài phải lớn hơn 0.')}else{let st=db.staff.find(s=>s.id===staffVal);if(!st)return toast('Chưa có nhân sự từ Google Sheet.');Object.assign(x,{stage:f.get('stage'),staff:st.name,days:Number(f.get('days')),rate:st.rate,allowance:Number(f.get('allowance')||0),status:f.get('status')});if(x.status==='Đã chốt'&&!x.days&&!x.allowance)return toast('Công hoặc phụ phí đã chốt phải lớn hơn 0.')}}if((type!=='labor'&&!x.amount)||(type==='costs'||type==='extras')&&!x.text)return toast('Vui lòng nhập đủ dữ liệu.');o[type].push(x);log(o,`${titles[type]}${x.amount?': '+money(x.amount):''}`);render();$('#quickDialog').close();openOrder(o.id,type);toast('Đã cập nhật');syncOrderToSupabase(o)}}
function confirmPayment(o,id){if(!['Kế toán','Giám đốc','Admin'].includes(user().role))return toast('Chỉ Kế toán được xác nhận khoản thu.');let p=o.payments.find(x=>x.id===id);p.status='Đã xác nhận';p.confirmedBy=user().name;log(o,`Xác nhận khoản thu ${money(p.amount)}`);render();openOrder(o.id,'payments');toast('Đã xác nhận khoản thu');syncOrderToSupabase(o)}
function deleteItem(o,kind,id){if(!confirm('Xóa mục này?'))return;o[kind]=o[kind].filter(x=>x.id!==id);log(o,'Xóa dữ liệu '+kind);render();openOrder(o.id,kind);syncOrderToSupabase(o)}
function renderReports(){let cs=db.orders.filter(o=>!o.deletedAt).map(o=>({o,c:calc(o)})),active=cs.filter(x=>x.o.stage!=='Hoàn công'),completed=cs.filter(x=>x.o.stage==='Hoàn công'),metrics=[['Đơn đang chạy',active.length],['Đã hoàn công',completed.length],['Giá trị đang chạy',money(active.reduce((s,x)=>s+x.c.revenue,0))],['Tổng đã thu',money(cs.reduce((s,x)=>s+x.c.confirmed,0))],['Công nợ phải thu',money(cs.reduce((s,x)=>s+Math.max(x.c.debt,0),0))],['Tổng lợi nhuận',money(cs.reduce((s,x)=>s+x.c.profit,0))],['Sắp đến hạn',active.filter(x=>x.o.due>=today()&&x.o.due<=datePlus(3)).length],['Quá hạn',active.filter(x=>x.o.due<today()).length]];$('#metrics').innerHTML=metrics.map(x=>`<div class="metric"><small>${x[0]}</small><strong>${x[1]}</strong></div>`).join('');renderReport($('.rTab.active')?.dataset.report||'orders')}
function renderReport(type){let cs=db.orders.filter(o=>!o.deletedAt).map(o=>({o,c:calc(o)}));if(type==='debt')cs=cs.filter(x=>x.c.debt>0).sort((a,b)=>b.c.debt-a.c.debt);if(type==='profit')cs.sort((a,b)=>a.c.profit-b.c.profit);if(type==='staff'){let allocatedByName={};db.orders.filter(o=>!o.deletedAt).forEach(o=>(o.labor||[]).filter(x=>x.status==='Đã chốt').forEach(x=>allocatedByName[x.staff]=(allocatedByName[x.staff]||0)+(x.days||0)));let rows=db.staff.map(s=>{let allocated=allocatedByName[s.name]||0,remain=Math.max(0,(s.actualDays||0)-allocated);return `<tr><td><b>${esc(s.name)}</b><br><small>${esc(s.code||s.email)}</small></td><td>${esc(s.dept||'—')}</td><td><span class="role-pill">${s.salaryType==='month'?'Lương tháng':s.salaryType==='hour'?'Lương giờ':'Lương ngày'}</span></td><td>${money(s.hourlySalary)}</td><td>${money(s.dailySalary)}</td><td>${money(s.monthlySalary)}</td><td>${money(s.configAllowance)}</td><td>${money(s.actualAllowance)}</td><td><b>${money(s.rate)}</b></td><td>${s.actualDays||0}</td><td>${allocated}</td><td class="${remain>0?'danger':''}">${remain}</td></tr>`}).join('');$('#reportContent').innerHTML=`<div class="sync-head"><div><b>Lương và nhân sự từ Google Sheet</b><br><small>${db.staffSyncedAt?'Đồng bộ lúc '+new Date(db.staffSyncedAt).toLocaleString('vi-VN')+' · kỳ '+(db.staffSyncedMonth||''):'Chưa đồng bộ'} · Tự đồng bộ khi sang tháng mới</small></div><button id="syncStaff" class="primary">↻ Đồng bộ ngay</button></div>${rows?`<table class="data salary-table"><thead><tr><th>Nhân sự</th><th>Bộ phận</th><th>Loại lương</th><th>Lương giờ</th><th>Lương ngày</th><th>Lương tháng</th><th>PC cấu hình</th><th>PC thực tế tháng</th><th>Đơn giá/công</th><th>Công Sheet</th><th>Đã phân bổ</th><th>Còn lại</th></tr></thead><tbody>${rows}</tbody></table>`:'<div class="empty">Chưa có nhân sự. Bấm Đồng bộ ngay.</div>'}`;$('#syncStaff').onclick=()=>syncStaffFromGoogle();return}let orderRows=cs.map(({o,c})=>`<tr data-open="${o.id}"><td><b>${esc(o.code)}</b></td><td>${esc(o.customer)}</td><td>${o.stage}</td><td>${esc(o.owner)}</td><td>${money(c.revenue)}</td><td>${money(c.confirmed)}</td><td class="${c.debt>0?'danger':''}">${money(c.debt)}</td><td>${money(c.costs)}</td><td class="${c.profit<0?'danger':''}">${money(c.profit)} (${c.margin.toFixed(1)}%)</td><td>${fmtDate(o.due)}</td></tr>`).join('');$('#reportContent').innerHTML=`<table class="data"><thead><tr><th>Mã đơn</th><th>Khách hàng</th><th>Trạng thái</th><th>Phụ trách</th><th>Giá trị</th><th>Đã thu</th><th>Công nợ</th><th>Chi phí</th><th>Lãi/lỗ</th><th>Ngày hẹn</th></tr></thead><tbody>${orderRows}</tbody></table>`;$$('[data-open]').forEach(x=>x.onclick=()=>openOrder(x.dataset.open))}
function parseCSV(text){let rows=[],row=[],cell='',quoted=false;for(let i=0;i<text.length;i++){let ch=text[i];if(ch==='"'){if(quoted&&text[i+1]==='"'){cell+='"';i++}else quoted=!quoted}else if(ch===','&&!quoted){row.push(cell);cell=''}else if((ch==='\n'||ch==='\r')&&!quoted){if(ch==='\r'&&text[i+1]==='\n')i++;row.push(cell);if(row.some(x=>x!==''))rows.push(row);row=[];cell=''}else cell+=ch}if(cell||row.length){row.push(cell);rows.push(row)}return rows}
function num(v){return Number(String(v||'').replace(/[^0-9.-]/g,''))||0}
async function syncStaffFromGoogle(silent=false){let btn=$('#syncStaff');if(btn){btn.disabled=true;btn.textContent='Đang đồng bộ...'}try{let base=`https://docs.google.com/spreadsheets/d/${SHEET_ID}/export?format=csv`,[empRes,payRes]=await Promise.all([fetch(`${base}&gid=${SHEET_EMP_GID}&t=${Date.now()}`),fetch(`${base}&gid=${SHEET_PAYROLL_GID}&t=${Date.now()}`)]);if(!empRes.ok||!payRes.ok)throw new Error('Không đọc được Sheet');let empRows=parseCSV(await empRes.text()),payRows=parseCSV(await payRes.text()),eh=empRows.shift().map(x=>x.trim()),ph=payRows.shift().map(x=>x.trim()),ei=n=>eh.indexOf(n),pi=n=>ph.indexOf(n);let payroll=payRows.map(r=>({month:r[pi('Tháng')],email:String(r[pi('Email')]||'').toLowerCase(),days:num(r[pi('Công Chuẩn')]),allowance:num(r[pi('Tổng Phụ Cấp')])})).filter(x=>x.email),latest=payroll.map(x=>x.month).filter(Boolean).sort().pop()||new Date().toISOString().slice(0,7),payMap=Object.fromEntries(payroll.filter(x=>x.month===latest).map(x=>[x.email,x]));db.staff=empRows.map(r=>{let email=String(r[ei('Email')]||'').trim(),type=String(r[ei('Loại Lương')]||'day').trim().toLowerCase(),hourly=num(r[ei('Lương Giờ')]),daily=num(r[ei('Lương Ngày')]),monthly=num(r[ei('Lương Tháng')]),p=payMap[email.toLowerCase()]||{},allowanceParts=['Phụ Cấp Xăng','Phụ Cấp Ăn Trưa Công Trình','Phụ Cấp Nước Công Trình','Phụ Cấp Cơm','Phụ Cấp Công Trình'].map(n=>num(r[ei(n)])),configAllowance=allowanceParts.reduce((a,b)=>a+b,0),baseRate=type==='month'?monthly/STANDARD_MONTH_DAYS:type==='hour'?hourly*8:daily,allowancePerDay=p.days>0?(p.allowance||0)/p.days:0;return{id:email.toLowerCase(),email,name:r[ei('Họ Tên')],code:r[ei('Mã Nhân Viên')],dept:r[ei('Bộ Phận')],position:r[ei('Chức Vụ')],salaryType:type,hourlySalary:hourly,dailySalary:daily,monthlySalary:monthly,configAllowance,actualAllowance:p.allowance||0,actualDays:p.days||0,month:latest,rate:Math.round(baseRate+allowancePerDay),status:r[ei('Trạng Thái')]}}).filter(x=>x.email&&x.name&&String(x.status).toLowerCase().includes('hoạt động'));db.staffSyncedAt=new Date().toISOString();db.staffSyncedMonth=new Date().toISOString().slice(0,7);save();render();if(!silent)toast(`Đã đồng bộ ${db.staff.length} nhân sự · dữ liệu lương kỳ ${latest}`);syncStaffToSupabase(db.staff)}catch(e){if(!silent)toast('Không thể đọc Google Sheet. Kiểm tra quyền chia sẻ hoặc mạng.');console.error(e)}finally{if(btn){btn.disabled=false;btn.textContent='↻ Đồng bộ ngay'}}}
function renderAccounts(){let active=db.users.filter(x=>x.active).length,admins=db.users.filter(x=>x.active&&x.role==='Admin').length;$('#accountStats').innerHTML=[['Tổng tài khoản',db.users.length],['Đang hoạt động',active],['Quản trị viên',admins]].map(x=>`<div class="metric"><small>${x[0]}</small><strong>${x[1]}</strong></div>`).join('');$('#accountsContent').innerHTML=`<table class="data account-table"><thead><tr><th>Người dùng</th><th>Tên đăng nhập</th><th>Vai trò</th><th>Điện thoại</th><th>Trạng thái</th><th>Thao tác</th></tr></thead><tbody>${db.users.map(u=>`<tr><td><div class="account-name"><span class="account-avatar">${esc(u.name.trim()[0]||'?')}</span><b>${esc(u.name)}</b></div></td><td>${esc(u.username)}</td><td><span class="role-pill">${u.role}</span></td><td>${esc(u.phone||'—')}</td><td><span class="status-pill ${u.active?'active':'inactive'}">● ${u.active?'Hoạt động':'Đã khóa'}</span></td><td><div class="row-actions"><button data-edit-user="${u.id}">Sửa</button><button data-toggle-user="${u.id}">${u.active?'Khóa':'Mở'}</button></div></td></tr>`).join('')}</tbody></table>`;$$('[data-edit-user]').forEach(b=>b.onclick=()=>openAccount(b.dataset.editUser));$$('[data-toggle-user]').forEach(b=>b.onclick=()=>toggleAccount(b.dataset.toggleUser));$('#backupUrl').value = db.backupUrl || '';$('#saveBackupUrlBtn').onclick = () => {db.backupUrl = $('#backupUrl').value.trim();save();toast('Đã lưu cấu hình URL sao lưu.');};$('#backupNowBtn').onclick = () => backupToGoogleDrive();$('#restoreBtn').onclick = () => listBackups();}
function openAccount(id){let u=id?db.users.find(x=>x.id===id):{id:uid(),name:'',username:'',password:'',role:'Quản lý đơn hàng',phone:'',active:true};$('#accountTitle').textContent=id?'Sửa tài khoản':'Tạo tài khoản';$('#accountBody').innerHTML=`<div class="formcontent"><div class="grid"><div class="field span2"><label>Họ và tên *</label><input name="name" value="${esc(u.name)}" required></div><div class="field"><label>Số điện thoại</label><input name="phone" value="${esc(u.phone)}"></div><div class="field"><label>Tên đăng nhập *</label><input name="username" value="${esc(u.username)}" required autocomplete="off"></div><div class="field"><label>Mật khẩu ${id?'(để trống nếu giữ nguyên)':'*'}</label><input type="password" name="password" autocomplete="new-password"></div><div class="field"><label>Vai trò</label><select name="role">${ROLES.map(r=>`<option ${r===u.role?'selected':''}>${r}</option>`)}</select></div></div></div><div class="modalactions"><button value="cancel" formnovalidate>Hủy</button><button type="button" id="saveAccount" class="primary">Lưu tài khoản</button></div>`;$('#accountDialog').showModal();$('#saveAccount').onclick=()=>{let f=new FormData($('#accountForm')),name=f.get('name').trim(),username=f.get('username').trim().toLowerCase(),password=f.get('password');if(!name||!username||(!id&&!password))return toast('Vui lòng nhập đủ họ tên, tên đăng nhập và mật khẩu.');if(db.users.some(x=>x.id!==u.id&&x.username.toLowerCase()===username))return toast('Tên đăng nhập đã tồn tại.');u.name=name;u.username=username;u.phone=f.get('phone').trim();u.role=f.get('role');if(password)u.password=password;if(!id){u.createdAt=new Date().toISOString();db.users.push(u)}render();$('#accountDialog').close();toast(id?'Đã cập nhật tài khoản':'Đã tạo tài khoản');syncUserToSupabase(u)}}
function toggleAccount(id){let u=db.users.find(x=>x.id===id);if(u.id===db.currentUser&&u.active)return toast('Không thể khóa tài khoản đang sử dụng.');if(u.role==='Admin'&&u.active&&db.users.filter(x=>x.active&&x.role==='Admin').length===1)return toast('Phải còn ít nhất một tài khoản Admin.');u.active=!u.active;render();toast(u.active?'Đã mở tài khoản':'Đã khóa tài khoản');syncUserToSupabase(u)}
function exportCsv(){let rows=[['Mã đơn','Khách hàng','Địa chỉ','Điện thoại','Trạng thái','Phụ trách','Giá trị','Đã thu','Công nợ','Chi phí','Lãi lỗ','Ngày hẹn']];db.orders.filter(o=>!o.deletedAt).forEach(o=>{let c=calc(o);rows.push([o.code,o.customer,o.address,o.phone,o.stage,o.owner,c.revenue,c.confirmed,c.debt,c.costs,c.profit,o.due])});let csv='\ufeff'+rows.map(r=>r.map(v=>'"'+String(v).replaceAll('"','""')+'"').join(',')).join('\r\n'),a=document.createElement('a');a.href=URL.createObjectURL(new Blob([csv],{type:'text/csv;charset=utf-8'}));a.download='bao-cao-gomita-'+today()+'.csv';a.click();URL.revokeObjectURL(a.href)}
function toast(s){let x=document.createElement('div');x.className='toast';x.textContent=s;$('#toast').append(x);setTimeout(()=>x.remove(),2600)}
$$('.nav').forEach(b=>b.onclick=()=>{if(b.dataset.view==='accounts'&&user().role!=='Admin')return toast('Chỉ Admin được quản lý tài khoản.');if(b.dataset.view==='trash'&&user().role!=='Admin')return toast('Chỉ Admin được truy cập Thùng rác.');$$('.nav,.view').forEach(x=>x.classList.remove('active'));b.classList.add('active');$('#'+b.dataset.view+'View').classList.add('active')});$$('.rTab').forEach(b=>b.onclick=()=>{$$('.rTab').forEach(x=>x.classList.remove('active'));b.classList.add('active');renderReport(b.dataset.report)});$('#newOrder').onclick=()=>openOrder();$('#newAccount').onclick=()=>openAccount();['search','statusFilter','priorityFilter'].forEach(id=>$('#'+id).oninput=renderBoard);$('#exportCsv').onclick=exportCsv;$('#printReport').onclick=()=>window.print();$('#loginForm').onsubmit=e=>{e.preventDefault();let f=new FormData(e.currentTarget),username=f.get('username').trim().toLowerCase(),password=f.get('password');let account;if(username==='admin'&&password==='123456'){account=db.users.find(x=>x.username.toLowerCase()==='admin');if(!account){account=INITIAL_ADMIN;db.users.push(INITIAL_ADMIN);save();syncUserToSupabase(INITIAL_ADMIN)}}else{account=db.users.find(x=>x.username.toLowerCase()===username)}if(!account||account.password!==password)return showLogin('Tên đăng nhập hoặc mật khẩu không đúng.');if(!account.active)return showLogin('Tài khoản này đã bị khóa. Vui lòng liên hệ Admin.');db.currentUser=account.id;enterApp()};$('#logoutButton').onclick=()=>showLogin();$('#currentName').onclick=openProfile;$('#profileButton').onclick=openProfile;$('#togglePassword').onclick=()=>{let p=$('#loginPassword');p.type=p.type==='password'?'text':'password'};$('#syncOnlineBtn')?.addEventListener('click',()=>syncFromSupabase());
init();


function getDaysInTrash(o){if(!o.deletedAt)return 0;return(Date.now()-new Date(o.deletedAt).getTime())/(1000*60*60*24)}
function restoreOrder(id){let o=db.orders.find(x=>x.id===id);if(!o)return;delete o.deletedAt;log(o,'Khôi phục đơn hàng từ thùng rác');render();toast('Đã khôi phục đơn hàng')}
function permanentDeleteOrder(id){let o=db.orders.find(x=>x.id===id);if(!o)return;if(getDaysInTrash(o)<7)return toast('Chưa đủ 7 ngày để xóa vĩnh viễn.');if(!confirm(`Xóa vĩnh viễn đơn hàng ${o.code}? Thao tác này không thể khôi phục.`))return;db.orders=db.orders.filter(x=>x.id!==id);render();toast('Đã xóa vĩnh viễn đơn hàng')}
function renderTrash(){let list=db.orders.filter(o=>o.deletedAt),rows=list.map(o=>{let diff=getDaysInTrash(o),canDel=diff>=7,left=Math.ceil(7-diff);return `<tr><td><b>${esc(o.code)}</b></td><td>${esc(o.customer)}</td><td>${esc(o.stage)}</td><td>${new Date(o.deletedAt).toLocaleDateString('vi-VN')}</td><td><span class="status-pill ${canDel?'active':'inactive'}">${canDel?'Đủ điều kiện':'Chờ '+left+' ngày'}</span></td><td><div class="row-actions"><button data-restore-order="${o.id}">Khôi phục</button><button class="danger" data-perm-delete="${o.id}" ${canDel?'':'disabled'}>Xóa vĩnh viễn</button></div></td></tr>`}).join('');$('#trashContent').innerHTML=rows?`<table class="data"><thead><tr><th>Mã đơn</th><th>Khách hàng</th><th>Trạng thái</th><th>Ngày xóa</th><th>Trạng thái xóa</th><th>Thao tác</th></tr></thead><tbody>${rows}</tbody></table>`:'<div class="empty">Thùng rác trống.</div>';$$('[data-restore-order]').forEach(b=>b.onclick=()=>restoreOrder(b.dataset.restoreOrder));$$('[data-perm-delete]').forEach(b=>b.onclick=()=>permanentDeleteOrder(b.dataset.permDelete))}

function checkAutoBackup(){if(!db.backupUrl)return;let last=db.lastBackupAt?new Date(db.lastBackupAt).getTime():0;if(Date.now()-last>7*24*60*60*1000){backupToGoogleDrive(true)}}
async function backupToGoogleDrive(silent=false){if(!db.backupUrl){if(!silent)toast('Vui lòng cấu hình URL Google Apps Script Web App.');return}let btn=$('#backupNowBtn');if(btn){btn.disabled=true;btn.textContent='Đang sao lưu...'}try{let response=await fetch(db.backupUrl,{method:'POST',mode:'cors',headers:{'Content-Type':'text/plain'},body:JSON.stringify(db)});let result=await response.json();if(result.success){db.lastBackupAt=new Date().toISOString();save();if(!silent)toast('Sao lưu dữ liệu lên Google Drive thành công.')}else{throw new Error(result.error||'Lỗi từ Apps Script')}}catch(e){console.error(e);if(!silent)toast('Lỗi khi sao lưu dữ liệu lên Google Drive.')}finally{if(btn){btn.disabled=false;btn.textContent='☁ Sao lưu ngay'}}}
async function listBackups(){if(!db.backupUrl)return toast('Vui lòng cấu hình URL Web App trước.');let listDiv=$('#backupList');listDiv.style.display='block';listDiv.innerHTML='<p><small>Đang tải danh sách bản sao lưu...</small></p>';try{let response=await fetch(`${db.backupUrl}?action=list`);let list=await response.json();if(!list||!list.length){listDiv.innerHTML='<p><small>Không tìm thấy bản sao lưu nào.</small></p>';return}listDiv.innerHTML=`<table class="data" style="margin-top:8px;font-size:12px;"><thead><tr><th>Tên bản sao lưu</th><th>Ngày tạo</th><th>Thao tác</th></tr></thead><tbody>${list.map(b=>`<tr><td><b>${esc(b.name)}</b></td><td>${new Date(b.created).toLocaleString('vi-VN')}</td><td><button class="primary" data-restore-id="${b.id}" style="min-height:28px;padding:3px 8px;font-size:11px;">Khôi phục</button></td></tr>`).join('')}</tbody></table>`;$$('[data-restore-id]').forEach(btn=>{btn.onclick=()=>restoreFromBackup(btn.dataset.restoreId)})}catch(e){console.error(e);listDiv.innerHTML='<p><small class="danger">Không thể tải danh sách bản sao lưu.</small></p>'}}
async function restoreFromBackup(id){if(!confirm('Khôi phục dữ liệu từ bản sao lưu này? Dữ liệu hiện tại trên thiết bị sẽ bị ghi đè!'))return;try{toast('Đang tải dữ liệu sao lưu...');let response=await fetch(`${db.backupUrl}?action=get&id=${id}`);let backupData=await response.json();if(backupData&&backupData.version){db=backupData;save();toast('Khôi phục dữ liệu thành công! Đang tải lại trang...');setTimeout(()=>location.reload(),1500)}else{toast('File sao lưu không đúng định dạng.')}}catch(e){console.error(e);toast('Lỗi khi khôi phục bản sao lưu.')}}
function openProfile(){let u=user();$('#accountTitle').textContent='Đổi thông tin & mật khẩu';$('#accountBody').innerHTML=`<div class="formcontent"><div class="grid"><div class="field span2"><label>Họ và tên *</label><input name="name" value="${esc(u.name)}" required></div><div class="field"><label>Số điện thoại</label><input name="phone" value="${esc(u.phone)}"></div><div class="field"><label>Tên đăng nhập *</label><input name="username" value="${esc(u.username)}" required autocomplete="username"></div><div class="field"><label>Mật khẩu mới (để trống nếu giữ nguyên)</label><input type="password" name="password" autocomplete="new-password" placeholder="Mật khẩu mới..."></div><div class="field"><label>Vai trò</label><input value="${esc(u.role)}" disabled></div></div></div><div class="modalactions"><button value="cancel" formnovalidate>Hủy</button><button type="button" id="saveProfileBtn" class="primary">Lưu thay đổi</button></div>`;$('#accountDialog').showModal();$('#saveProfileBtn').onclick=()=>{let f=new FormData($('#accountForm')),name=f.get('name').trim(),username=f.get('username').trim().toLowerCase(),password=f.get('password');if(!name||!username)return toast('Vui lòng nhập đủ họ tên và tên đăng nhập.');if(db.users.some(x=>x.id!==u.id&&x.username.toLowerCase()===username))return toast('Tên đăng nhập đã tồn tại.');u.name=name;u.username=username;u.phone=f.get('phone').trim();if(password)u.password=password;save();render();$('#accountDialog').close();toast('Đã cập nhật thông tin cá nhân');syncUserToSupabase(u)}}

function payItem(o,type,id){if(!['Kế toán','Giám đốc','Admin'].includes(user().role))return toast('Chỉ Kế toán được xác nhận thanh toán.');let list=o[type]||[],item=list.find(x=>x.id===id);if(item){item.status='Đã thanh toán';log(o,`Xác nhận thanh toán ${type==='extras'?'phát sinh':'chi phí'} "${item.text}" số tiền ${money(item.amount)}`);render();openOrder(o.id,type);toast('Đã xác nhận thanh toán thành công.');syncOrderToSupabase(o)}}
function openEditLabor(o,id){let x=o.labor.find(item=>item.id===id);if(!x)return;if(!canAddData('labor'))return toast('Bạn không có quyền sửa công nhân sự.');$('#quickTitle').textContent='Sửa nhân sự / công';$('#quickBody').innerHTML=`<div class="formcontent"><div class="grid"><div class="field"><label>Nhân sự</label><input value="${esc(x.staff)}" disabled></div><div class="field"><label>Công đoạn</label><input value="${esc(x.stage)}" disabled></div><div class="field"><label>Số công *</label><input type="number" step="0.25" min="0" name="days" value="${x.days}"></div><div class="field"><label>Phụ phí công tác</label><input type="number" name="allowance" value="${x.allowance||0}" min="0"></div><div class="field"><label>Trạng thái</label><select name="status"><option value="Chưa chốt" ${x.status==='Chưa chốt'?'selected':''}>Chưa chốt</option><option value="Đã chốt" ${x.status==='Đã chốt'?'selected':''}>Đã chốt</option></select></div></div></div><div class="modalactions"><button value="cancel" formnovalidate>Hủy</button><button type="button" id="saveEditLaborBtn" class="primary">Lưu</button></div>`;$('#quickDialog').showModal();$('#saveEditLaborBtn').onclick=()=>{let f=new FormData($('#quickForm')),days=Number(f.get('days')),allowance=Number(f.get('allowance')||0),status=f.get('status');if(status==='Đã chốt'&&!days&&!allowance)return toast('Công hoặc phụ phí đã chốt phải lớn hơn 0.');x.days=days;x.allowance=allowance;x.status=status;log(o,`Cập nhật công thợ ${x.staff} bước ${x.stage} thành ${days} công + ${money(allowance)} phụ phí (${status})`);render();$('#quickDialog').close();openOrder(o.id,'labor');toast('Đã cập nhật công thợ.');syncOrderToSupabase(o)}}

